# Module providing geometric shape classes for testing cross-module inheritance

class Shape:
    @abstract
    def area(self) -> float: ...

    @abstract
    def perimeter(self) -> float: ...

class Rectangle(Shape):
    width: float
    height: float

    def __init__(self, width: float, height: float):
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

class Circle(Shape):
    radius: float
    PI: float = 3.14159

    def __init__(self, radius: float):
        self.radius = radius

    @override
    def area(self) -> float:
        return self.PI * self.radius * self.radius

    @override
    def perimeter(self) -> float:
        return 2.0 * self.PI * self.radius

