# Module providing mathematical utility functions and constants

from shapes import Rectangle, Circle

const GOLDEN_RATIO: float = 1.61803

def add(a: float, b: float) -> float:
    return a + b

def factorial(n: int) -> int:
    if n <= 1:
        return 1
    return n * factorial(n - 1)

def describe_shape(shape: Rectangle) -> str:
    area_val: float = shape.area()
    perim_val: float = shape.perimeter()
    return f"Rectangle {shape.width}x{shape.height}: area={area_val:.2f}, perimeter={perim_val:.2f}"

def circle_stats(c: Circle) -> tuple[float, float]:
    return (c.area(), c.perimeter())
